function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return -1;
    }

    // 1. Compute Prefix Maximums (PMax[i] = max(nums[0...i]))
    const pMax = new Array(n);
    pMax[0] = nums[0];
    for (let i = 1; i < n; i++) {
        pMax[i] = Math.max(pMax[i - 1], nums[i]);
    }

    // 2. Compute Suffix Minimums (SMin[i] = min(nums[i...n-1]))
    const sMin = new Array(n);
    sMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        sMin[i] = Math.min(sMin[i + 1], nums[i]);
    }

    // 3. Iterate and find the smallest stable index
    for (let i = 0; i < n; i++) {
        // Instability value U_i = PMax[i] - SMin[i]
        const instabilityValue = pMax[i] - sMin[i];

        if (instabilityValue <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}
